import sys
from dataclasses import dataclass

@dataclass(frozen=True)
class Point:
    x: int
    y: int

def solve(data: str) -> str:
    x, y = map(int, data.split())
    point = Point(x, y)
    return f"{abs(point.x) + abs(point.y)}\n{point!r}"

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
